#!/usr/bin/env python3
# /// script
# name: resolve-repo-context
# purpose: Resolve and verify worktree content authority and shared Git coordination authority.
# inputs: ["argv: --repo-root PATH? --config PATH --mode read|write"]
# outputs: ["stdout: JSON repository/worktree context"]
# requires-python = ">=3.10"
# dependencies: []
# contexts: [A, B, C, E]
# network: false
# write-scope: none
# ///
from __future__ import annotations

import argparse
import hashlib
import os
import re
import sys
from pathlib import Path
from typing import Any

from _common import ContractError, contained, dump, git, load_json, stable_id


DEFAULT_CONTENT_ROOTS = {
    "issues": "issues",
    "tasks": "tasks",
    "specifications": "specs",
    "architecture": "architecture",
    "features": "features",
    "documents": "docs",
    "system_spec": "system-spec",
}
DEFAULT_LOCAL_STATE = {
    "graph": ".dev-graph/state/graph.json",
    "cache": ".dev-graph/cache",
    "locks": ".dev-graph/locks",
}
GITHUB_REMOTE = re.compile(
    r"^(?:https?://github\.com/|ssh://git@github\.com/|git@github\.com:)([^/]+)/(.+?)(?:\.git)?/?$",
    re.IGNORECASE,
)


def discover(explicit: str | None) -> tuple[Path, str]:
    choices: list[tuple[str, str]] = []
    if explicit:
        choices.append((explicit, "explicit --repo-root"))
    trusted = os.environ.get("CLAUDE_PROJECT_DIR")
    if trusted:
        choices.append((trusted, "CLAUDE_PROJECT_DIR"))
    cp = __import__("subprocess").run(
        ["git", "rev-parse", "--show-toplevel"], text=True, capture_output=True, check=False
    )
    if cp.returncode == 0:
        choices.append((cp.stdout.strip(), "git toplevel"))
    for parent in (Path.cwd(), *Path.cwd().parents):
        if (parent / ".git").exists() or (parent / ".dev-graph").is_dir():
            choices.append((str(parent), "cwd marker"))
            break
    if not choices:
        raise ContractError("repository root cannot be resolved")
    root = Path(choices[0][0]).expanduser().resolve(strict=True)
    actual = Path(git(["rev-parse", "--show-toplevel"], root)).resolve(strict=True)
    if root != actual:
        raise ContractError(f"selected root is not current worktree root: {root} != {actual}")
    if trusted and Path(trusted).expanduser().resolve(strict=True) != root:
        raise ContractError("--repo-root and CLAUDE_PROJECT_DIR disagree")
    return root, choices[0][1]


def repository_id_for(remote: str, common: Path) -> str:
    """Derive the durable repository identity from the canonical authority."""
    match = GITHUB_REMOTE.fullmatch(remote.strip()) if remote else None
    if match:
        owner, repository = match.groups()
        return f"github:{owner}/{repository.removesuffix('.git')}"
    digest = hashlib.sha256(str(common.resolve(strict=True)).encode("utf-8")).hexdigest()
    return f"local:sha256:{digest}"


def _absolute_git_path(raw: str, root: Path) -> Path:
    path = Path(raw)
    return (root / path).resolve(strict=True) if not path.is_absolute() else path.resolve(strict=True)


def verify_common_ownership(root: Path, git_dir: Path, common: Path) -> None:
    """Prove that the selected worktree and common directory are one repository."""
    try:
        objects = _absolute_git_path(git(["rev-parse", "--git-path", "objects"], root), root)
        config = _absolute_git_path(git(["rev-parse", "--git-path", "config"], root), root)
        common_objects = (common / "objects").resolve(strict=True)
        common_config = (common / "config").resolve(strict=True)
    except OSError as exc:
        raise ContractError(f"git common dir authority is incomplete: {common}: {exc}") from exc
    if objects != common_objects:
        raise ContractError("git common dir objects authority does not belong to selected repository")
    if config != common_config:
        raise ContractError("git common dir config authority does not belong to selected repository")
    if git_dir != common:
        marker = git_dir / "commondir"
        if not marker.is_file() or marker.is_symlink():
            raise ContractError(f"worktree git dir has no trusted commondir marker: {marker}")
        try:
            declared = (git_dir / marker.read_text(encoding="utf-8").strip()).resolve(strict=True)
        except OSError as exc:
            raise ContractError(f"invalid worktree commondir marker: {marker}: {exc}") from exc
        if declared != common:
            raise ContractError(f"worktree commondir mismatch: {declared} != {common}")
    root_remote = git(["remote", "get-url", "origin"], root, check=False)
    common_remote = git(["--git-dir", str(common), "remote", "get-url", "origin"], root, check=False)
    if root_remote != common_remote:
        raise ContractError("worktree and git common dir resolve different origin remotes")


def _validate_relative(raw: Any, label: str) -> Path:
    if not isinstance(raw, str) or not raw or "\x00" in raw:
        raise ContractError(f"{label} must be a non-empty repository-relative path")
    relative = Path(raw)
    if relative.is_absolute() or ".." in relative.parts:
        raise ContractError(f"{label} escapes repository authority: {raw}")
    return relative


def resolve_declared_path(root: Path, raw: Any, label: str, *, reject_leaf_symlink: bool) -> Path:
    """Resolve an existing target or its longest existing parent without escaping root."""
    relative = _validate_relative(raw, label)
    candidate = root / relative
    current = root
    for part in relative.parts:
        current = current / part
        if current.is_symlink():
            try:
                target = current.resolve(strict=True)
            except OSError as exc:
                raise ContractError(f"broken content symlink for {label}: {current}: {exc}") from exc
            contained(target, root)
            if reject_leaf_symlink:
                raise ContractError(f"content root path must not traverse a symlink: {label}={current}")
        if not current.exists() and not current.is_symlink():
            break
    try:
        resolved = candidate.resolve(strict=True) if candidate.exists() or candidate.is_symlink() else candidate.resolve(strict=False)
    except OSError as exc:
        raise ContractError(f"cannot resolve {label}: {candidate}: {exc}") from exc
    contained(resolved, root, must_exist=False)
    return resolved


def resolve_config_paths(root: Path, config: dict[str, Any] | None) -> tuple[dict[str, str], dict[str, str]]:
    config = config or {}
    policy = config.get("path_policy") or {}
    if not isinstance(policy, dict):
        raise ContractError("path_policy must be an object")
    forbidden = (
        policy.get("authority") not in {None, "caller-repository"}
        or policy.get("allow_outside_repository") not in {None, False}
        or policy.get("follow_content_symlinks_outside_repository") not in {None, False}
    )
    if forbidden:
        raise ContractError("path_policy weakens caller-repository containment")
    content = config.get("content_roots") or DEFAULT_CONTENT_ROOTS
    local = config.get("local_state") or DEFAULT_LOCAL_STATE
    if not isinstance(content, dict) or not isinstance(local, dict):
        raise ContractError("content_roots and local_state must be objects")
    resolved_content = {
        key: str(resolve_declared_path(root, value, f"content_roots.{key}", reject_leaf_symlink=True))
        for key, value in sorted(content.items())
    }
    resolved_local = {
        key: str(resolve_declared_path(root, value, f"local_state.{key}", reject_leaf_symlink=False))
        for key, value in sorted(local.items())
    }
    return resolved_content, resolved_local


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--repo-root")
    parser.add_argument("--config", default=".dev-graph/config.json")
    parser.add_argument("--mode", choices=("read", "write"), default="read")
    args = parser.parse_args()
    root, trust = discover(args.repo_root)
    common_raw = git(["rev-parse", "--git-common-dir"], root)
    common = Path(common_raw)
    if not common.is_absolute():
        common = root / common
    common = common.resolve(strict=True)
    git_dir_raw = git(["rev-parse", "--git-dir"], root)
    git_dir = Path(git_dir_raw)
    if not git_dir.is_absolute():
        git_dir = root / git_dir
    git_dir = git_dir.resolve(strict=True)
    verify_common_ownership(root, git_dir, common)
    remote = git(["remote", "get-url", "origin"], root, check=False)
    repository_id = repository_id_for(remote, common)
    config_arg = Path(args.config)
    if config_arg.is_absolute():
        config_path = contained(config_arg, root, must_exist=False)
    else:
        config_path = root / _validate_relative(args.config, "config")
    config = None
    diagnostics: list[str] = []
    if config_path.exists() or config_path.is_symlink():
        try:
            config_path = contained(config_path, root)
        except OSError as exc:
            raise ContractError(f"broken repository config symlink: {config_path}: {exc}") from exc
        config = load_json(config_path)
        if not isinstance(config, dict):
            raise ContractError("repo config must be a JSON object")
        configured = config.get("repository_id") if isinstance(config, dict) else None
        if configured and configured != repository_id:
            raise ContractError("repo config repository_id does not match derived repository")
    else:
        diagnostics.append("config_missing")
    content_roots, local_state_paths = resolve_config_paths(root, config)
    branch = git(["symbolic-ref", "--quiet", "--short", "HEAD"], root, check=False) or None
    head = git(["rev-parse", "HEAD"], root)
    default_ref = git(["symbolic-ref", "--quiet", "refs/remotes/origin/HEAD"], root, check=False)
    default_branch = default_ref.rsplit("/", 1)[-1] if default_ref else (
        ((config or {}).get("worktrees") or {}).get("default_branch") if isinstance(config, dict) else None
    )
    if not default_branch:
        default_branch = "main"
        diagnostics.append("default_branch_fallback_main")
    worktree_id = stable_id("wt_", repository_id, str(root))
    coord = common / "dev-graph"
    plugin_source = Path(__file__).resolve().parents[1]
    trusted = os.environ.get("CLAUDE_PROJECT_DIR")
    result = {
        "repo_root": str(root), "repository_id": repository_id, "worktree_id": worktree_id,
        "git_common_dir": str(common), "git_dir": str(git_dir), "branch": branch,
        "head_sha": head, "default_branch": default_branch,
        "root_trust_evidence": {"selected_by": trust, "git_toplevel_verified": True,
                                "claude_project_dir_verified": not trusted or Path(trusted).resolve() == root,
                                "git_common_dir_ownership_verified": True},
        "content_roots": {"repository": str(root), **content_roots},
        "local_state_paths": {"config": str(config_path), **local_state_paths},
        "coordination_paths": {"root": str(coord), "leases": str(coord / "leases.json"),
                               "events": str(coord / "events.json")},
        "plugin_source": str(plugin_source), "mode": args.mode, "diagnostics": diagnostics,
    }
    dump(result)
    return 0


if __name__ == "__main__":
    try:
        raise SystemExit(main())
    except (ContractError, OSError) as exc:
        print(str(exc), file=sys.stderr)
        raise SystemExit(1)

#!/usr/bin/env python3
# /// script
# name: render-graph-html
# purpose: Deterministically render a task graph as dependency-free static HTML/SVG.
# inputs: ["argv: --graph FILE --out FILE"]
# outputs: ["file: static HTML", "stdout: JSON result"]
# requires-python = ">=3.10"
# dependencies: []
# contexts: [A, B, C, E]
# network: false
# write-scope: argv --out only
# ///
from __future__ import annotations

import argparse
import hashlib
import html
import json
import os
import sys
import tempfile
from pathlib import Path

from _common import ContractError, dump


def main() -> int:
    parser = argparse.ArgumentParser(); parser.add_argument("--graph", required=True); parser.add_argument("--out", required=True)
    args = parser.parse_args(); source = Path(args.graph).resolve(strict=True); out = Path(args.out).resolve(strict=False)
    if source == out: raise ContractError("output must not overwrite graph input")
    try:
        input_bytes = source.read_bytes()
        data = json.loads(input_bytes.decode("utf-8"))
    except (OSError, UnicodeDecodeError, json.JSONDecodeError) as exc:
        raise ContractError(f"invalid JSON {source}: {exc}") from exc
    input_sha256 = hashlib.sha256(input_bytes).hexdigest()
    nodes = data.get("nodes", []) if isinstance(data, dict) else data
    if not isinstance(nodes, list): raise ContractError("graph nodes must be an array")
    normalized = []
    for raw in nodes:
        if not isinstance(raw, dict): raise ContractError("each node must be an object")
        node_id = raw.get("graph_node_id") or raw.get("id")
        if not isinstance(node_id, str): raise ContractError("node id is required")
        parent_feature = raw.get("parent_feature")
        if parent_feature is not None and not isinstance(parent_feature, str):
            raise ContractError("parent_feature must be a string when present")
        normalized.append({"id": node_id, "title": str(raw.get("title", node_id)),
                           "status": str(raw.get("status", "draft")), "kind": str(raw.get("artifact_kind", raw.get("kind", "task"))),
                           "depends_on": sorted(raw.get("depends_on", [])), "parent_feature": parent_feature})
    normalized.sort(key=lambda x: x["id"]); ids = {x["id"] for x in normalized}
    dangling = sorted({d for n in normalized for d in n["depends_on"] if d not in ids})
    if dangling: raise ContractError(f"dangling dependencies: {dangling}")
    dangling_parents = sorted({n["parent_feature"] for n in normalized if n["parent_feature"] and n["parent_feature"] not in ids})
    if dangling_parents: raise ContractError(f"dangling parent_feature references: {dangling_parents}")
    children_by_feature: dict[str, list[dict[str, object]]] = {}
    for node in normalized:
        if node["parent_feature"]:
            children_by_feature.setdefault(str(node["parent_feature"]), []).append(node)
    for node in normalized:
        children = children_by_feature.get(node["id"], []) if node["kind"] == "feature" else []
        node["progress"] = (
            {"done": sum(child["status"] == "done" for child in children), "total": len(children)}
            if children else None
        )
    progress_by_feature = {
        str(node["id"]): node["progress"] or {"done": 0, "total": 0}
        for node in normalized
        if node["kind"] == "feature"
    }
    feature_progress = {
        "aggregate": {
            "done": sum(item["done"] for item in progress_by_feature.values()),
            "total": sum(item["total"] for item in progress_by_feature.values()),
        },
        "by_feature": progress_by_feature,
    }
    width, row_h = 1000, 72; height = max(160, 80 + len(normalized) * row_h)
    y = {node["id"]: 60 + i * row_h for i, node in enumerate(normalized)}
    lines = []
    for node in normalized:
        for dep in node["depends_on"]:
            lines.append(f'<path d="M 360 {y[dep]} C 500 {y[dep]}, 500 {y[node["id"]]}, 640 {y[node["id"]]}"/>')
    cards = []
    for node in normalized:
        safe_id, safe_title = html.escape(node["id"]), html.escape(node["title"])
        progress = node["progress"]
        progress_label = f' · {progress["done"]}/{progress["total"]}' if progress else ""
        cards.append(f'<g class="node status-{html.escape(node["status"])}" data-id="{safe_id}" data-text="{safe_title.lower()}">' 
                     f'<rect x="40" y="{y[node["id"]]-24}" width="320" height="48" rx="8"/>'
                     f'<text x="54" y="{y[node["id"]]-3}">{safe_id}</text><text class="title" x="54" y="{y[node["id"]]+15}">{safe_title}</text>'
                     f'<rect x="640" y="{y[node["id"]]-18}" width="220" height="36" rx="18"/><text x="660" y="{y[node["id"]]+5}">{html.escape(node["status"])} · {html.escape(node["kind"])}{progress_label}</text></g>')
    payload = json.dumps(normalized, ensure_ascii=False, sort_keys=True).replace("<", "\\u003c")
    document = f'''<!doctype html><html lang="en"><meta charset="utf-8"><meta name="viewport" content="width=device-width">
<title>dev-graph</title><style>body{{font:14px system-ui;margin:0;background:#0b1020;color:#e5e7eb}}header{{position:sticky;top:0;padding:16px;background:#111827;z-index:2}}input{{padding:8px;width:min(420px,70vw)}}svg{{min-width:{width}px;height:{height}px}}path{{stroke:#64748b;fill:none;stroke-width:2}}.node rect{{fill:#1f2937;stroke:#64748b}}.node text{{fill:#f8fafc}}.node .title{{fill:#cbd5e1;font-size:12px}}.status-done rect{{stroke:#22c55e}}.hidden{{display:none}}</style>
<header><strong>dev-graph</strong> <input id="q" aria-label="Filter nodes" placeholder="Filter id/title/status"></header>
<svg viewBox="0 0 {width} {height}" role="img" aria-label="Task dependency graph"><g class="edges">{''.join(lines)}</g>{''.join(cards)}</svg>
<script type="application/json" id="graph-data">{payload}</script><script>const q=document.querySelector('#q');q.addEventListener('input',()=>{{const s=q.value.toLowerCase();document.querySelectorAll('.node').forEach(n=>n.classList.toggle('hidden',!((n.dataset.id+' '+n.dataset.text+' '+n.className.baseVal).toLowerCase().includes(s))))}});</script></html>'''
    out.parent.mkdir(parents=True, exist_ok=True); fd, temp = tempfile.mkstemp(prefix=f".{out.name}.", dir=out.parent)
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as stream: stream.write(document); stream.flush(); os.fsync(stream.fileno())
        os.replace(temp, out)
    finally:
        try: os.unlink(temp)
        except FileNotFoundError: pass
    output_sha256 = hashlib.sha256(out.read_bytes()).hexdigest()
    dump({
        "ok": True,
        "out": str(out),
        "nodes": len(normalized),
        "edges": sum(len(x["depends_on"]) for x in normalized),
        "input_sha256": input_sha256,
        "output_sha256": output_sha256,
        "feature_progress": feature_progress,
    })
    return 0


if __name__ == "__main__":
    try: raise SystemExit(main())
    except ContractError as exc: print(str(exc), file=sys.stderr); raise SystemExit(1)

#!/usr/bin/env python3
# /// script
# name: validate-graph-schema
# purpose: Perform side-effect-free fail-closed validation of canonical dev-graph nodes, artifacts, and feature packages.
# inputs: ["argv: --graph FILE --repo-root PATH?"]
# outputs: ["stdout: JSON validation report"]
# requires-python = ">=3.10"
# dependencies: []
# contexts: [A, B, C, E]
# network: false
# write-scope: none
# ///
from __future__ import annotations

import argparse
import json
import re
import sys
from collections import Counter, defaultdict
from datetime import date, datetime
from pathlib import Path, PurePosixPath
from typing import Any
from urllib.parse import urlsplit

from _common import ContractError, contained, dump, load_json

PLUGIN_ROOT = Path(__file__).resolve().parents[1]
SCHEMA_PATH = PLUGIN_ROOT / "schemas" / "graph-node.schema.json"
TEMPLATE_CONTRACT_PATH = PLUGIN_ROOT / "templates" / "template-contract.json"
PHASES = {f"P{i:02d}" for i in range(1, 14)}
ROOT_BY_KIND = {
    "issue": "issues",
    "task": "tasks",
    "specification": "specs",
    "architecture": "architecture",
    "feature": "features",
    "document": "docs",
}


def nodes_of(data: Any) -> list[dict[str, Any]]:
    values = data.get("nodes") if isinstance(data, dict) else data
    if not isinstance(values, list) or not all(isinstance(item, dict) for item in values):
        raise ContractError("graph must be an array or an object with nodes[]")
    return values


def _is_type(value: Any, expected: str) -> bool:
    return {
        "null": value is None,
        "object": isinstance(value, dict),
        "array": isinstance(value, list),
        "string": isinstance(value, str),
        "boolean": isinstance(value, bool),
        "integer": isinstance(value, int) and not isinstance(value, bool),
        "number": isinstance(value, (int, float)) and not isinstance(value, bool),
    }.get(expected, True)


def _format_ok(value: str, expected: str) -> bool:
    try:
        if expected == "date":
            date.fromisoformat(value)
        elif expected == "date-time":
            datetime.fromisoformat(value.replace("Z", "+00:00"))
        elif expected == "uri":
            return bool(urlsplit(value).scheme)
    except ValueError:
        return False
    return True


def _schema_fallback(value: Any, schema: Any, root: dict[str, Any], path: str = "$") -> list[tuple[str, str]]:
    """Deterministic Draft 2020-12 subset used if jsonschema is unavailable."""
    if schema is True:
        return []
    if schema is False or not isinstance(schema, dict):
        return [(path, "value is forbidden" if schema is False else "invalid schema object")]
    findings: list[tuple[str, str]] = []
    reference = schema.get("$ref")
    if isinstance(reference, str):
        if not reference.startswith("#/"):
            return [(path, f"external schema reference is forbidden: {reference}")]
        target: Any = root
        try:
            for part in reference[2:].split("/"):
                target = target[part.replace("~1", "/").replace("~0", "~")]
        except (KeyError, TypeError):
            return [(path, f"unresolved schema reference: {reference}")]
        findings.extend(_schema_fallback(value, target, root, path))
    for child in schema.get("allOf", []):
        findings.extend(_schema_fallback(value, child, root, path))
    if "if" in schema and not _schema_fallback(value, schema["if"], root, path) and "then" in schema:
        findings.extend(_schema_fallback(value, schema["then"], root, path))
    expected = schema.get("type")
    if expected is not None:
        choices = expected if isinstance(expected, list) else [expected]
        if not any(_is_type(value, choice) for choice in choices):
            return findings + [(path, f"expected type {choices}, got {type(value).__name__}")]
    if "const" in schema and value != schema["const"]:
        findings.append((path, f"expected const {schema['const']!r}"))
    if "enum" in schema and value not in schema["enum"]:
        findings.append((path, f"not in enum {schema['enum']!r}"))
    if isinstance(value, str):
        if len(value) < schema.get("minLength", 0):
            findings.append((path, "string is shorter than minLength"))
        if "pattern" in schema and re.search(schema["pattern"], value) is None:
            findings.append((path, f"does not match {schema['pattern']}"))
        if "format" in schema and not _format_ok(value, schema["format"]):
            findings.append((path, f"invalid {schema['format']} format"))
    if isinstance(value, (int, float)) and not isinstance(value, bool):
        if "minimum" in schema and value < schema["minimum"]:
            findings.append((path, "below minimum"))
        if "maximum" in schema and value > schema["maximum"]:
            findings.append((path, "above maximum"))
    if isinstance(value, list):
        if len(value) < schema.get("minItems", 0):
            findings.append((path, "too few items"))
        if "maxItems" in schema and len(value) > schema["maxItems"]:
            findings.append((path, "too many items"))
        if schema.get("uniqueItems"):
            packed = [json.dumps(item, sort_keys=True, separators=(",", ":")) for item in value]
            if len(packed) != len(set(packed)):
                findings.append((path, "items are not unique"))
        items = schema.get("items")
        if isinstance(items, dict):
            for index, item in enumerate(value):
                findings.extend(_schema_fallback(item, items, root, f"{path}[{index}]"))
        if "contains" in schema and not any(not _schema_fallback(item, schema["contains"], root, path) for item in value):
            findings.append((path, "contains constraint is not satisfied"))
    if isinstance(value, dict):
        for key in schema.get("required", []):
            if key not in value:
                findings.append((path, f"missing required property {key}"))
        properties = schema.get("properties", {})
        for key, child in properties.items():
            if key in value:
                findings.extend(_schema_fallback(value[key], child, root, f"{path}.{key}"))
        additional = schema.get("additionalProperties", True)
        unknown = sorted(set(value) - set(properties))
        if additional is False and unknown:
            findings.append((path, f"unknown properties {unknown}"))
        elif isinstance(additional, dict):
            for key in unknown:
                findings.extend(_schema_fallback(value[key], additional, root, f"{path}.{key}"))
    return findings


def schema_findings(node: dict[str, Any], schema: dict[str, Any], index: int) -> list[dict[str, str]]:
    node_id = str(node.get("graph_node_id") or node.get("id") or f"nodes[{index}]")
    try:
        from jsonschema import Draft202012Validator, FormatChecker  # type: ignore
    except ImportError:
        raw = _schema_fallback(node, schema, schema)
    else:
        try:
            Draft202012Validator.check_schema(schema)
        except Exception as exc:
            raise ContractError(f"invalid canonical graph schema {SCHEMA_PATH}: {exc}") from exc
        validator = Draft202012Validator(schema, format_checker=FormatChecker())
        errors = sorted(
            validator.iter_errors(node),
            key=lambda err: (tuple(str(part) for part in err.absolute_path), err.message),
        )
        raw = [
            ("$" + "".join(f"[{part}]" if isinstance(part, int) else f".{part}" for part in error.absolute_path), error.message)
            for error in errors
        ]
    return [
        {"node": node_id, "code": "schema_violation", "detail": f"{path}: {detail}"}
        for path, detail in raw
    ]


def _scalar(raw: str) -> Any:
    value = raw.strip()
    try:
        return json.loads(value)
    except json.JSONDecodeError:
        if (value.startswith("'") and value.endswith("'")) or (value.startswith('"') and value.endswith('"')):
            return value[1:-1]
        return value


def frontmatter_of(path: Path) -> dict[str, Any]:
    try:
        lines = path.read_text(encoding="utf-8").splitlines()
    except OSError as exc:
        raise ContractError(f"cannot read artifact {path}: {exc}") from exc
    if not lines or lines[0].strip() != "---":
        raise ContractError(f"artifact has no YAML frontmatter: {path}")
    result: dict[str, Any] = {}
    for line in lines[1:]:
        if line.strip() == "---":
            return result
        match = re.match(r"^([A-Za-z_][A-Za-z0-9_-]*):(?:\s*(.*))?$", line)
        if match:
            result[match.group(1)] = _scalar(match.group(2) or "")
    raise ContractError(f"artifact frontmatter is not terminated: {path}")


def _repo_root_for(graph: Path, explicit: str | None) -> Path:
    if explicit:
        root = Path(explicit).expanduser().resolve(strict=True)
        contained(graph, root)
        return root
    resolved = graph.resolve(strict=True)
    for parent in resolved.parents:
        if parent.name == ".dev-graph":
            return parent.parent
    raise ContractError("--repo-root is required when --graph is outside the canonical .dev-graph tree")


def artifact_findings(
    nodes: list[dict[str, Any]], repo_root: Path | None, template_contract: dict[str, Any]
) -> list[dict[str, str]]:
    findings: list[dict[str, str]] = []
    required_frontmatter = set((template_contract.get("common_frontmatter") or {}).get("required") or [])
    for index, node in enumerate(nodes):
        node_id = str(node.get("graph_node_id") or node.get("id") or f"nodes[{index}]")
        kind = node.get("artifact_kind", node.get("kind"))
        raw_path = node.get("file_path")
        if kind in ROOT_BY_KIND and isinstance(raw_path, str):
            logical = PurePosixPath(raw_path)
            if logical.is_absolute() or ".." in logical.parts or not logical.parts or logical.parts[0] != ROOT_BY_KIND[kind]:
                findings.append({"node": node_id, "code": "path_parity_error", "detail": f"{kind} must be under {ROOT_BY_KIND[kind]}/"})
                continue
        if repo_root is None or not isinstance(raw_path, str):
            continue
        candidate = repo_root / raw_path
        try:
            # Missing canonical artifacts are readiness gaps, not containment
            # failures.  Resolve without requiring existence, then let the
            # is_file check below classify the missing artifact explicitly.
            artifact = contained(candidate, repo_root, must_exist=False)
        except (ContractError, OSError) as exc:
            findings.append({"node": node_id, "code": "artifact_path_invalid", "detail": str(exc)})
            continue
        if not artifact.is_file():
            findings.append({"node": node_id, "code": "artifact_missing", "detail": raw_path})
            continue
        try:
            frontmatter = frontmatter_of(artifact)
        except ContractError as exc:
            findings.append({"node": node_id, "code": "frontmatter_invalid", "detail": str(exc)})
            continue
        for key in sorted(required_frontmatter - set(frontmatter)):
            findings.append({"node": node_id, "code": "frontmatter_missing", "detail": key})
        for key in ("graph_node_id", "artifact_kind", "file_path", "template_id", "template_version"):
            if key in node and frontmatter.get(key) != node.get(key):
                findings.append({"node": node_id, "code": "frontmatter_parity_error", "detail": key})
    return findings


def domain_findings(nodes: list[dict[str, Any]]) -> list[dict[str, str]]:
    findings: list[dict[str, str]] = []
    ids: list[str] = []
    by_id: dict[str, dict[str, Any]] = {}
    for index, node in enumerate(nodes):
        node_id = node.get("graph_node_id") or node.get("id")
        loc = str(node_id or f"nodes[{index}]")
        if not isinstance(node_id, str) or not node_id:
            findings.append({"node": loc, "code": "missing_id", "detail": "graph_node_id required"})
            continue
        ids.append(node_id)
        by_id[node_id] = node
        kind = node.get("artifact_kind", node.get("kind"))
        if kind is not None and kind not in ROOT_BY_KIND:
            findings.append({"node": loc, "code": "invalid_kind", "detail": str(kind)})
        if node.get("status") not in {"draft", "active", "blocked", "done", "closed", "tombstoned"}:
            findings.append({"node": loc, "code": "invalid_status", "detail": str(node.get("status"))})
        dependencies = node.get("depends_on", [])
        if not isinstance(dependencies, list) or any(not isinstance(value, str) for value in dependencies):
            findings.append({"node": loc, "code": "invalid_dependencies", "detail": "depends_on must be string[]"})
        if node.get("tracker_binding") == "beads" and (node.get("github_publication") or {}).get("mode") != "local_only":
            findings.append({"node": loc, "code": "beads_publication", "detail": "beads requires local_only"})
        if node.get("tracker_binding") == "github" and node.get("beads_linkage") is not None:
            findings.append({"node": loc, "code": "binding_collision", "detail": "github cannot have beads_linkage"})
        if node.get("status") == "active":
            readiness = (node.get("implementation_readiness") or {}).get("status")
            if node.get("confirmation_status") != "confirmed" or node.get("evaluation_status") != "pass" or readiness != "complete":
                findings.append({"node": loc, "code": "active_not_ready", "detail": "active requires confirmed/pass/complete"})
        if node.get("tracker_binding") == "repo-config-default":
            findings.append({"node": loc, "code": "unresolved_tracker_binding", "detail": "durable graph cannot retain repo-config-default"})
    for duplicate, count in Counter(ids).items():
        if count > 1:
            findings.append({"node": duplicate, "code": "duplicate_id", "detail": str(count)})
    reference_fields = ("depends_on", "related_nodes", "architecture_refs")
    for index, node in enumerate(nodes):
        node_id = str(node.get("graph_node_id") or node.get("id") or f"nodes[{index}]")
        for field in reference_fields:
            for reference in node.get(field, []) if isinstance(node.get(field, []), list) else []:
                if reference not in by_id:
                    code = "dangling_dependency" if field == "depends_on" else "dangling_reference"
                    findings.append({"node": node_id, "code": code, "detail": f"{field}:{reference}"})
        parent = node.get("parent_feature")
        if isinstance(parent, str) and parent not in by_id:
            findings.append({"node": node_id, "code": "dangling_reference", "detail": f"parent_feature:{parent}"})

    state: dict[str, int] = {}

    def visit(node_id: str) -> None:
        if state.get(node_id) == 1:
            findings.append({"node": node_id, "code": "dependency_cycle", "detail": node_id})
            return
        if state.get(node_id) == 2:
            return
        state[node_id] = 1
        dependencies = by_id[node_id].get("depends_on", [])
        for dependency in dependencies if isinstance(dependencies, list) else []:
            if dependency in by_id:
                visit(dependency)
        state[node_id] = 2

    for node_id in by_id:
        visit(node_id)

    children: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for node in nodes:
        if isinstance(node.get("parent_feature"), str):
            children[node["parent_feature"]].append(node)
    order = {phase: int(phase[1:]) for phase in PHASES}
    for feature_id, feature in ((node_id, node) for node_id, node in by_id.items() if node.get("artifact_kind") == "feature"):
        members = children.get(feature_id, [])
        if members or feature.get("status") == "done":
            packages = {member.get("feature_package_id") for member in members}
            phases = [member.get("phase_ref") for member in members]
            if packages == {None} or len(packages) != 1 or set(phases) != PHASES or len(members) != 13:
                findings.append({"node": feature_id, "code": "feature_package_not_exact_13", "detail": f"count={len(members)} phases={sorted(str(value) for value in set(phases))}"})
        for child in members:
            current = order.get(child.get("phase_ref"), 0)
            for dependency in child.get("depends_on", []):
                target = by_id.get(dependency, {})
                if target.get("parent_feature") == feature_id and order.get(target.get("phase_ref"), 0) >= current:
                    findings.append({"node": str(child.get("graph_node_id") or child.get("id") or "?"), "code": "non_forward_phase_dependency", "detail": dependency})
        if feature.get("status") == "done":
            if any(member.get("status") != "done" for member in members):
                findings.append({"node": feature_id, "code": "premature_feature_done", "detail": "all 13 children must be done"})
            for phase in {"P07", "P10", "P11"}:
                child = next((member for member in members if member.get("phase_ref") == phase), {})
                if not (child.get("completion_evidence") or {}).get("evidence_refs"):
                    findings.append({"node": feature_id, "code": "feature_evidence_missing", "detail": phase})
    return findings


def validate(
    nodes: list[dict[str, Any]], schema: dict[str, Any] | None = None,
    *, repo_root: Path | None = None, template_contract: dict[str, Any] | None = None,
) -> list[dict[str, str]]:
    canonical_schema = schema or load_json(SCHEMA_PATH)
    if not isinstance(canonical_schema, dict):
        raise ContractError(f"canonical graph schema must be an object: {SCHEMA_PATH}")
    contract = template_contract or load_json(TEMPLATE_CONTRACT_PATH)
    if not isinstance(contract, dict):
        raise ContractError(f"template contract must be an object: {TEMPLATE_CONTRACT_PATH}")
    findings = [item for index, node in enumerate(nodes) for item in schema_findings(node, canonical_schema, index)]
    findings.extend(domain_findings(nodes))
    findings.extend(artifact_findings(nodes, repo_root, contract))
    return sorted(findings, key=lambda item: (item["node"], item["code"], item["detail"]))


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--graph", required=True)
    parser.add_argument("--repo-root")
    args = parser.parse_args()
    graph = Path(args.graph).expanduser().resolve(strict=True)
    nodes = nodes_of(load_json(graph))
    violations = validate(nodes, repo_root=_repo_root_for(graph, args.repo_root))
    missing = sorted({
        item["detail"] for item in violations
        if item["code"] in {"frontmatter_missing", "artifact_missing"}
        or (item["code"] == "schema_violation" and "required property" in item["detail"])
    })
    dump({
        "valid": not violations,
        "implementation_readiness": "complete" if not violations else "incomplete",
        "missing_sections": missing,
        "schema": str(SCHEMA_PATH),
        "violations": violations,
    })
    return 0 if not violations else 1


if __name__ == "__main__":
    try:
        raise SystemExit(main())
    except (ContractError, OSError) as exc:
        print(str(exc), file=sys.stderr)
        raise SystemExit(2)

